import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader.js';
import { DRACOLoader } from 'three/examples/jsm/loaders/DRACOLoader.js';
import { FBXLoader } from 'three/examples/jsm/loaders/FBXLoader.js';

/**
 * AssetLoader
 * -----------
 * Loads GLB character models and applies an *animation name mapping* so the
 * rest of the engine can reference canonical game names (e.g. `punch_light`)
 * regardless of what the source pack called its clips (e.g. `Punching`).
 *
 * Several of our character GLBs are exported with Draco mesh compression.
 * GLTFLoader needs an explicit DRACOLoader instance to decode them — the
 * decoder files live in /public/draco/ so the app stays offline-capable
 * for the Android build.
 */
export class AssetLoader {
  constructor() {
    this._gltf = new GLTFLoader();
    this._fbx = new FBXLoader();
    this._draco = new DRACOLoader();
    this._draco.setDecoderPath('/draco/');
    this._draco.setDecoderConfig({ type: 'wasm' });
    this._gltf.setDRACOLoader(this._draco);

    this._textureLoader = new THREE.TextureLoader();
    this._gltfCache = new Map();
    this._fbxCache = new Map();
    this._textureCache = new Map();
  }

  dispose() {
    this._draco?.dispose();
  }

  /**
   * Load a GLB and remap its embedded animations.
   *
   * @param {object} opts
   * @param {string} opts.url - Path to the .glb file (under /public/...).
   * @param {Record<string, string>} [opts.animationMap]
   * @param {Record<string, string>} [opts.externalAnimations] - Canonical name to standalone FBX animation URL.
   * @returns {Promise<{scene: THREE.Group, clips: Record<string, THREE.AnimationClip>, mixer: THREE.AnimationMixer, raw: object}>}
   */
  async loadCharacter({ url, animationMap = {}, externalAnimations = {} }) {
    const gltf = await this._loadGltf(url);

    const scene = gltf.scene;
    scene.traverse((obj) => {
      if (obj.isMesh) {
        obj.castShadow = true;
        obj.receiveShadow = true;
      }
    });

    const sourceClips = gltf.animations ?? [];
    const clips = this._remapClips(sourceClips, animationMap);
    await this._loadExternalAnimationClips(clips, externalAnimations);
    const mixer = new THREE.AnimationMixer(scene);

    return { scene, clips, mixer, raw: gltf };
  }

  /**
   * Build a record of canonical-name → AnimationClip using the supplied map.
   * Case-insensitive on the source side so GLBs whose clip names differ
   * by capitalisation still resolve.
   */
  _remapClips(sourceClips, animationMap) {
    const bySource = new Map(sourceClips.map((c) => [c.name.toLowerCase(), c]));
    const out = {};
    const missing = [];

    for (const [gameName, sourceName] of Object.entries(animationMap)) {
      const clip = bySource.get(String(sourceName).toLowerCase());
      if (clip) {
        const cloned = clip.clone();
        cloned.name = gameName;
        out[gameName] = cloned;
      } else {
        missing.push(`${gameName} ← "${sourceName}"`);
      }
    }

    if (missing.length > 0) {
      console.warn(
        `[AssetLoader] Missing ${missing.length} animation(s):\n  ` +
          missing.join('\n  '),
      );
    }

    return out;
  }

  async _loadExternalAnimationClips(clips, externalAnimations = {}) {
    for (const [gameName, url] of Object.entries(externalAnimations)) {
      try {
        const fbx = await this._loadFbx(url);
        const clip = fbx.animations?.[0];
        if (!clip) {
          console.warn(`[AssetLoader] External animation "${gameName}" has no clips: ${url}`);
          continue;
        }
        const cloned = clip.clone();
        cloned.name = gameName;
        this._stripRootMotion(cloned);
        clips[gameName] = cloned;
      } catch (err) {
        console.warn(`[AssetLoader] Failed to load external animation "${gameName}" from ${url}`, err);
      }
    }
  }

  _stripRootMotion(clip) {
    // Standalone Mixamo victim clips often animate the hips/root position.
    // The fighter state machine already controls world X/Y for throws, so
    // leaving root motion in the clip can launch the model above the stage.
    clip.tracks = clip.tracks.filter((track) => {
      const name = track.name.toLowerCase();
      const isPosition = name.endsWith('.position');
      const isRootLike =
        name.includes('hips.position') ||
        name.includes('root.position') ||
        name.includes('armature.position');
      return !(isPosition && isRootLike);
    });
    clip.resetDuration();
  }

  /** Cache wrapper around GLTFLoader.loadAsync. */
  _loadGltf(url) {
    if (this._gltfCache.has(url)) return this._gltfCache.get(url);
    const p = this._gltf.loadAsync(url);
    this._gltfCache.set(url, p);
    return p;
  }

  _loadFbx(url) {
    if (this._fbxCache.has(url)) return this._fbxCache.get(url);
    const p = this._fbx.loadAsync(url);
    this._fbxCache.set(url, p);
    return p;
  }

  /** Load a texture for stage parallax layers. */
  loadTexture(url) {
    if (this._textureCache.has(url)) return this._textureCache.get(url);
    const tex = this._textureLoader.load(url);
    tex.colorSpace = THREE.SRGBColorSpace;
    tex.anisotropy = 4;
    this._textureCache.set(url, tex);
    return tex;
  }
}
